// frontend/src/pages/Home.jsx
import React, { useEffect } from "react";
import "../styles/home.css";                 // path to the CSS you uploaded
import flatpickr from "flatpickr";
import "flatpickr/dist/flatpickr.min.css";  // flatpickr styles

export default function Home() {
  useEffect(() => {
    // ----------------- SLIDER (adapted from your home.js) -----------------
    const slides = Array.from(document.querySelectorAll(".slide"));
    const dotsWrap = document.getElementById("dots");
    const page = document.getElementById("page");
    let current = 0;

    function makeDots() {
      if (!dotsWrap) return;
      slides.forEach((_, i) => {
        const d = document.createElement("div");
        d.className = "dot" + (i === 0 ? " active" : "");
        d.dataset.index = i;
        d.addEventListener("click", () => goTo(i));
        dotsWrap.appendChild(d);
      });
    }

    function update() {
      slides.forEach((s, i) => s.classList.toggle("active", i === current));
      if (dotsWrap) {
        Array.from(dotsWrap.children).forEach((d, i) =>
          d.classList.toggle("active", i === current)
        );
      }
      if (page) page.textContent = (current + 1) + " / " + slides.length;
    }

    function goTo(i) {
      current = (i + slides.length) % slides.length;
      update();
    }
    function next() { goTo(current + 1); }
    function prev() { goTo(current - 1); }

    const nextBtn = document.getElementById("next");
    const prevBtn = document.getElementById("prev");
    const sliderEl = document.getElementById("slider");

    if (nextBtn) nextBtn.addEventListener("click", next);
    if (prevBtn) prevBtn.addEventListener("click", prev);

    window.addEventListener("keydown", function (e) {
      if (e.key === "ArrowRight") next();
      if (e.key === "ArrowLeft") prev();
    });

    let autoplay = setInterval(next, 6000);
    if (sliderEl) {
      sliderEl.addEventListener("mouseenter", () => clearInterval(autoplay));
      sliderEl.addEventListener("mouseleave", () => (autoplay = setInterval(next, 6000)));
    }

    makeDots();
    update();

    // ----------------- RESERVATION (counter + flatpickr) -----------------
    document.querySelectorAll(".counter button").forEach(button => {
      button.addEventListener("click", () => {
        const target = button.dataset.target;
        const span = document.getElementById(`${target}-count`);
        if (!span) return;
        let value = parseInt(span.textContent, 10) || 0;
        if (button.classList.contains("plus")) {
          value++;
        } else if (button.classList.contains("minus")) {
          const min = target === "adult" ? 1 : 0;
          value = Math.max(min, value - 1);
        }
        span.textContent = value;
      });
    });

    const dateDisplay = document.getElementById("date-display");
    // init flatpickr on the hidden input
    const fp = flatpickr("#datePicker", {
      mode: "range",
      dateFormat: "M d",
      minDate: "today",
      defaultDate: [
        new Date(),
        new Date(new Date().setDate(new Date().getDate() + 1))
      ],
      onChange: function (selectedDates) {
        if (selectedDates.length === 2 && dateDisplay) {
          let start = selectedDates[0];
          let end = selectedDates[1];
          dateDisplay.textContent =
            start.toLocaleDateString("en-US", { month: "short", day: "numeric" }) +
            " - " +
            end.toLocaleDateString("en-US", { month: "short", day: "numeric" });
        }
      }
    });
    if (dateDisplay) {
      dateDisplay.addEventListener("click", () => {
        if (fp && fp.open) fp.open();
      });
    }

    // Cleanup on unmount
    return () => {
      // remove interval/listeners to avoid duplicates
      clearInterval(autoplay);
      if (nextBtn) nextBtn.removeEventListener("click", next);
      if (prevBtn) prevBtn.removeEventListener("click", prev);
      window.removeEventListener("keydown", () => {});
    };
  }, []);

  // ----------------- JSX markup (keeps IDs/classes used by the JS) -----------------
  return (
    <div className="home-page">
      {/* -- Slider / Hero -- */}
      <div id="slider" className="slider">
        <div className="slide active" style={{ backgroundImage: "url('/assets/glamp1.jpg')" }}></div>
        <div className="slide" style={{ backgroundImage: "url('/assets/glamp2.jpg')" }}></div>
        <div className="slide" style={{ backgroundImage: "url('/assets/glamp3.jpg')" }}></div>

        <div className="nav">
          <div className="nav-inner">
            <div className="brand">
              The Edens Glamp
              <span className="stars">★★★★★</span>
            </div>
            <div className="menu">
              <a href="#rooms">Rooms</a>
              <a href="#services">Services</a>
              <a className="reserve" href="#reservation">Reserve</a>
            </div>
          </div>
        </div>

        <div className="hero-wrap">
          <div className="arch">
            <div className="arch-inner">
              <div className="stars-row">★★★★★</div>
              <h1>The Edens Glamp</h1>
              <p className="lead">Welcome — this React site was converted from your original PHP site. Replace this content with your page markup.</p>
              <a className="cta" href="#reservation">Book Now</a>
            </div>
          </div>
        </div>

        <button id="prev" className="arrow left"><span>&lt;</span></button>
        <button id="next" className="arrow right"><span>&gt;</span></button>

